game.onUpdate(function () {
    for (let value22 of sprites.allOfKind(SpriteKind.Player)) {
        value22.setPosition(playerShadow.x, playerShadow.y - 10)
    }
    for (let value22 of sprites.allOfKind(SpriteKind.Enemy)) {
        if (spriteFx.distanceBetween(mySprite, value22) < 120) {
            spriteFx.smoothRotate(value22, spriteFx.angleBetween(mySprite, value22) - 180, 100)
        } else {
            timer.throttle("action", 1000, function () {
                spriteFx.smoothRotate(value22, randint(0, 180), 500)
                if (Math.percentChance(60)) {
                    spriteutils.setVelocityAtAngle(value22, spriteFx.rotation(value22), 30)
                }
            })
        }
    }
    if (controller.A.isPressed()) {
        controller.moveSprite(playerShadow, 140, 140)
        isSprinting = 1
    } else {
        controller.moveSprite(playerShadow, 100, 100)
        isSprinting = 0
    }
})
